1. **urlMatchesPatterns** (tab-matching.ts:10-15) — add optional excludePatterns parameter:
```typescript
export const urlMatchesPatterns = (url: string, patterns: string[], excludePatterns?: string[]): boolean => {
  let matched = false;
  for (const pattern of patterns) {
    if (matchPattern(url, pattern)) { matched = true; break; }
  }
  if (!matched) return false;
  if (excludePatterns) {
    for (const pattern of excludePatterns) {
      if (matchPattern(url, pattern)) return false;
    }
  }
  return true;
};
```

2. **findAllMatchingTabs** (tab-matching.ts:107-148) — post-filter after chrome.tabs.query:
After collecting allMatches, filter out tabs whose URL matches any exclude pattern:
```typescript
const excludePatterns = plugin.excludePatterns ?? [];
const filtered = excludePatterns.length > 0
